use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/assets
use cardano/transaction.{Transaction}

pub type VoteRedeemer {
  nft_asset_name: ByteArray,
  vote_option: ByteArray,
  voter_pkh: VerificationKeyHash,
}

validator ballot_mint(
  nft_policy_id: assets.PolicyId,
  allowed_options: List<ByteArray>,
) {
  mint(redeemer: VoteRedeemer, policy_id: assets.PolicyId, self: Transaction) {
    let VoteRedeemer { nft_asset_name, vote_option, voter_pkh } = redeemer

    // 1. Voter must have signed the transaction
    let voter_signed =
      list.has(self.extra_signatories, voter_pkh)

    // 2. Vote option must be one of the allowed choices
    let valid_option =
      list.has(allowed_options, vote_option)

    // 3. Exactly one ballot token is minted, named after the NFT asset name
    let minted_qty =
      assets.quantity_of(self.mint, policy_id, nft_asset_name)
    let exactly_one_ballot = minted_qty == 1

    // 4. The voter's input must contain the NFT
    let holds_nft =
      list.any(
        self.inputs,
        fn(input) {
          assets.quantity_of(input.output.value, nft_policy_id, nft_asset_name) == 1
        },
      )

    voter_signed && valid_option && exactly_one_ballot && holds_nft
  }

  else(_) {
    fail
  }
}
