  message_id: ByteArray
}

pub type Redeemer {
  message_body: ByteArray
}

validator hyperlane_message_lock {
  spend(
    datum: Option<Datum>,
    redeemer: Redeemer,
    _own_ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      Some(d) -> {
        let computed_id = crypto.keccak_256(redeemer.message_body)
        computed_id == d.message_id
      }
      None -> False
    }
  }
}
```

This validator replicates Hyperlane's message ID derivation: funds locked at this script can only be spent when the caller provides the original message body whose `keccak256` hash matches the committed `message_id` in the datum.

