use cardano/assets
use cardano/transaction.{Transaction}

const bls12_381_scalar_prime: Int =
  52435875175126190479447740508185965837690552500527637822603658699938581184513

pub type Redeemer {
  field_element: Int,
  claimed_inverse: Int,
}

validator finite_field_mint {
  mint(
    redeemer: Redeemer,
    policy_id: ByteArray,
    self: Transaction,
  ) -> Bool {
    let p = bls12_381_scalar_prime
    let a = redeemer.field_element
    let inv = redeemer.claimed_inverse

    // Check the claimed inverse is valid: a * inv ≡ 1 (mod p)
    let inverse_valid = a * inv % p == 1

    // Check exactly 1 token is minted under this policy
    let minted_tokens = assets.tokens(self.mint, policy_id)
    let total_minted =
      minted_tokens
        |> assets.to_dict
        |> fn(_) { True }
    let mint_count =
      assets.flatten(self.mint)
        |> list.filter(fn(triple) {
            let (pid, _name, qty) = triple
            pid == policy_id && qty == 1
          })
        |> list.length

    inverse_valid && mint_count == 1
  }
}
