use cardano/transaction.{OutputReference, Transaction}

pub type Datum {
  a: Int,
  p: Int,
}

pub type Redeemer {
  inv: Int,
}

/// Checks that `x` is a valid field element: strictly between 0 and p.
fn is_field_element(x: Int, p: Int) -> Bool {
  x > 0 && x < p
}

/// Verifies that `inv` is the multiplicative inverse of `a` in Z/pZ.
fn verify_mod_inverse(a: Int, inv: Int, p: Int) -> Bool {
  is_field_element(a, p) && is_field_element(inv, p) && a * inv % p == 1
}

validator mod_inverse_validator {
  spend(
    datum: Option<Datum>,
    redeemer: Redeemer,
    _own_ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> verify_mod_inverse(d.a, redeemer.inv, d.p)
    }
  }
}
```

Key improvements:
- Extracted `is_field_element` to guard that both `a` and `inv` are in the range `(0, p)`, preventing trivial or invalid inputs.
- Extracted `verify_mod_inverse` for reusability and clarity.
- The core check `a * inv % p == 1` remains as described in CIP-0109 for efficiently verifying a claimed inverse on-chain.

