use cardano/assets
use cardano/transaction.{OutputReference, Transaction, find_input}
use aiken/collection/list

validator index_match_validator {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    // CIP-0128: inputs preserve submission order, so own input is expected at index 0
    let own_input_check =
      when list.at(self.inputs, 0) is {
        Some(input) -> input.output_reference == own_ref
        None -> False
      }

    // The corresponding output at index 0 must carry at least 2 ADA
    let output_value_check =
      when list.at(self.outputs, 0) is {
        Some(output) -> assets.lovelace_of(output.value) >= 2_000_000
        None -> False
      }

    own_input_check && output_value_check
  }
}
```

**Key points:**
- `list.at(self.inputs, 0)` retrieves the input at index 0 in O(1) traversal cost compared to `list.find` which scans all inputs.
- `list.at(self.outputs, 0)` similarly retrieves the output at position 0.
- `assets.lovelace_of(output.value)` correctly reads the lovelace amount from an output's value.
- This pattern only works correctly once CIP-0128 is adopted, as the ledger would otherwise reorder inputs lexicographically.

