pub type MintingRedeemer {
  amount: Int,
  asset_name: ByteArray,
}

validator programmable_logic_minting(minting_logic_cred: Credential) {
  mint(redeemer: MintingRedeemer, policy_id: PolicyId, self: Transaction) -> Bool {
    // Verify the minting logic credential is invoked via a withdrawal
    let cred_invoked =
      list.any(
        self.redeemers,
        fn(pair) {
          when pair.1st is {
            transaction.Withdraw(cred) -> cred == minting_logic_cred
            _ -> False
          }
        },
      )

    // Verify the minted amount matches the redeemer
    let minted_qty =
      assets.quantity_of(self.mint, policy_id, redeemer.asset_name)

    cred_invoked && minted_qty == redeemer.amount && redeemer.amount > 0
  }

  else(_) {
    fail
  }
}
