validator my_programmable_token(issuer_key: VerificationKeyHash) {
  mint(redeemer: ByteArray, policy_id: PolicyId, self: Transaction) -> Bool {
    // Check the issuer has signed the transaction
    let issuer_signed = list.has(self.extra_signatories, issuer_key)

    // Check the minted quantity of the token (using redeemer as asset name) is positive
    let minted_qty = assets.quantity_of(self.mint, policy_id, redeemer)
    let nonzero_mint = minted_qty > 0

    // Check that this policy's token actually appears in the mint field
    let policy_present =
      list.any(
        assets.policies(self.mint),
        fn(pid) { pid == policy_id },
      )

    issuer_signed && nonzero_mint && policy_present
  }

  else(_) {
    fail
  }
}
