```aiken
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/assets
use cardano/transaction.{Transaction, Output}

pub type Datum {
  drep_vkh: VerificationKeyHash,
}

pub type Redeemer {
  donation_basis_points: Int,
  total_rewards: Int,
}

validator drep_compensation {
  withdraw(
    redeemer: Redeemer,
    _account: Credential,
    self: Transaction,
  ) -> Bool {
    let Redeemer { donation_basis_points, total_rewards } = redeemer

    // donationBasisPoints encodes thousandths: 5 => 0.5% => 5/1000
    let required_donation = total_rewards * donation_basis_points / 1000

    // donation_basis_points must be positive and at most 1000 (100%)
    let valid_basis_points =
      donation_basis_points > 0 && donation_basis_points <= 1000

    // Verify that total lovelace sent to outputs covers the required donation
    // (off-chain tooling is responsible for routing to the DRep address;
    //  here we simply confirm the arithmetic constraint is satisfiable)
    let sufficient_donation =
      list.any(
        self.outputs,
        fn(output: Output) -> Bool {
          assets.lovelace_of(output.value) >= required_donation
        },
      )

    valid_basis_points && sufficient_donation
  }
}
```

```aiken
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}

pub type CompensationDatum {
  drep_vkh: VerificationKeyHash,
  donation_basis_points: Int,
  total_rewards: Int,
}

validator drep_compensation_spend {
  spend(
    datum: Option<CompensationDatum>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let CompensationDatum {
          drep_vkh,
          donation_basis_points,
          total_rewards,
        } = d

        // Validate basis points range: 1..1000
        let valid_basis_points =
          donation_basis_points >= 1 && donation_basis_points <= 1000

        // Calculate required donation in lovelace
        // donationBasisPoints encodes thousandths per CIP-0149
        let required_donation =
          total_rewards * donation_basis_points / 1000

        // DRep must sign the transaction
        let drep_signed =
          list.has(self.extra_signatories, drep_vkh)

        // At least one output must carry the required donation amount
        let donation_covered =
          list.any(
            self.outputs,
            fn(output) {
              assets.lovelace_of(output.value) >= required_donation
            },
          )

        valid_basis_points && drep_signed && donation_covered
      }
    }
  }
}
