use aiken/collection/list
use cardano/transaction.{Transaction, OutputReference}

// Emulate multiIndexArray using list.at — O(n*m) but functionally equivalent.
// list.at returns Option<a>, so we filter_map to skip out-of-bounds safely,
// or fail explicitly by using expect inside map.
fn multi_index(arr: List<Int>, indices: List<Int>) -> List<Int> {
  list.filter_map(indices, fn(i) { list.at(arr, i) })
}

type Datum {
  array: List<Int>,
  expected: List<Int>,
}

type Redeemer {
  indices: List<Int>,
}

validator emulate_multi_index_array {
  spend(
    datum: Option<Datum>,
    redeemer: Redeemer,
    _own_ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let result = multi_index(d.array, redeemer.indices)
        result == d.expected
      }
    }
  }
}
```

**Notes:**
- `list.at(arr, i)` returns `Option<Int>`; `filter_map` silently drops `None` (out-of-bounds). If you want strict failure on bad indices, use `expect Some(v) = list.at(arr, i)` inside a `map`.
- This is O(n × m) because `list.at` itself is O(n). Once CIP-0156's `multiIndexArray` builtin lands, it will be O(m) with O(1) per lookup.

```aiken
use aiken/collection/list
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

type MintRedeemer {
  asset_names: List<ByteArray>,
  indices: List<Int>,
}

// Emula multiIndexArray seleccionando elementos por índice.
fn multi_index_bytes(
  arr: List<ByteArray>,
  indices: List<Int>,
) -> List<ByteArray> {
  list.filter_map(indices, fn(i) { list.at(arr, i) })
}

validator selective_mint {
  mint(
    redeemer: MintRedeemer,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    // Seleccionamos los nombres de activos según los índices del redeemer.
    let selected = multi_index_bytes(redeemer.asset_names, redeemer.indices)

    // Verificamos que cada nombre seleccionado se acuñe exactamente en cantidad 1.
    list.all(
      selected,
      fn(name) {
        assets.quantity_of(self.mint, policy_id, name) == 1
      },
    )
  }
}
```

**Notas:**
- `multi_index_bytes` emula `multiIndexArray` usando `list.at` + `list.filter_map`.
- Una vez disponible el builtin de CIP-0156, esta lógica se simplificaría a una llamada directa a `multiIndexArray`.
- `assets.quantity_of` verifica la cantidad acuñada del token con ese `policy_id` y `asset_name`.

